 3→/**
 4→ * Union-Find to group constellation links into connected components (chains).
 5→ * Returns an array of chains, where each chain is an array of constellation link objects.
 6→ */
 7→export const computeConstellationChains = (constellations) => {
 8→    if (!Array.isArray(constellations) || constellations.length === 0) return [];
 9→
10→    const parent = new Map();
11→    const rank = new Map();
12→
13→    const find = (x) => {
14→        if (!parent.has(x)) {
15→            parent.set(x, x);
16→            rank.set(x, 0);
17→        }
18→        if (parent.get(x) !== x) {
19→            parent.set(x, find(parent.get(x)));
20→        }
21→        return parent.get(x);
22→    };
23→
24→    const union = (a, b) => {
25→        const rootA = find(a);
26→        const rootB = find(b);
27→        if (rootA === rootB) return;
28→
29→        const rankA = rank.get(rootA) || 0;
30→        const rankB = rank.get(rootB) || 0;
31→        if (rankA < rankB) {
32→            parent.set(rootA, rootB);
33→        } else if (rankA > rankB) {
34→            parent.set(rootB, rootA);
35→        } else {
36→            parent.set(rootB, rootA);
37→            rank.set(rootA, rankA + 1);
38→        }
39→    };
40→
41→    // Build union-find over star IDs
42→    for (const link of constellations) {
43→        union(link.star_id_a, link.star_id_b);
44→    }
45→
46→    // Group links by their chain root
47→    const chainMap = new Map();
48→    for (const link of constellations) {
49→        const root = find(link.star_id_a);
50→        if (!chainMap.has(root)) {
51→            chainMap.set(root, []);
52→        }
53→        chainMap.get(root).push(link);
54→    }
55→
56→    return Array.from(chainMap.values());
57→};
58→
59→/**
60→ * Assigns a consistent color from STAR_COLORS to each chain.
61→ * Returns a Map<constellationId, colorHex>.
62→ */
63→export const assignChainColors = (chains) => {
64→    const colorMap = new Map();
65→
66→    chains.forEach((chain, i) => {
67→        const color = STAR_COLORS[i % STAR_COLORS.length];
68→        for (const link of chain) {
69→            colorMap.set(link.id, color);
70→        }
71→    });
72→
73→    return colorMap;
74→};
